const item = $input.first();
const body = item.json.realEstateAds ?? item.json.body?.realEstateAds ?? item.json;
const ads = Array.isArray(body) ? body : (body.realEstateAds || []);
return ads.map(ad => ({
  json: {
    source: 'bienici',
    id_site: ad.id || '',
    titre: ad.title || '',
    description: (ad.description || '').replace(/<[^>]+>/g, ' ').trim().slice(0, 500),
    ville: ad.city || ad.district?.name || '',
    quartier: ad.district?.libelle || ad.district?.name || '',
    adresse: '',
    pieces: ad.roomsQuantity ?? null,
    surface_m2: ad.surfaceArea ?? null,
    loyer_cc: ad.price ?? null,
    charges: ad.charges ?? null,
    meuble: ad.isFurnished ?? null,
    url: `https://www.bienici.com/annonce/location/${(ad.city || '').toLowerCase().replace(/\s+/g, '-')}-${ad.postalCode || ''}/${ad.id || ''}`,
    date_publication: ad.publicationDate || null
  }
}));

const allItems = [];
for (const item of $input.all()) {
  const j = item.json;
  const html = (j.data != null && typeof j.data === 'string') ? j.data : (j.body != null && typeof j.body === 'string') ? j.body : '';
  let source = j.source || '';
  if (html && !source) {
    if (/bienici\.com|bien'ici/i.test(html)) source = 'bienici';
    else if (/seloger/i.test(html)) source = 'seloger';
    else source = 'inconnu';
  }
  if (html && !j.titre && !j.loyer_cc && !j.surface_m2) {
    continue;
  }
  if (!j.titre && (j.loyer_cc == null || j.loyer_cc === 0) && (j.surface_m2 == null || j.surface_m2 === 0)) {
    continue;
  }
  allItems.push({
    json: {
      source: source || 'inconnu',
      id_site: j.id_site || '',
      titre: j.titre || '',
      description: j.description || '',
      ville: j.ville || '',
      quartier: j.quartier || '',
      adresse: j.adresse || '',
      pieces: j.pieces ?? null,
      surface_m2: j.surface_m2 ?? null,
      loyer_cc: j.loyer_cc ?? null,
      charges: j.charges ?? null,
      meuble: j.meuble ?? null,
      url: j.url || '',
      date_publication: j.date_publication ?? null
    }
  });
}
return allItems;

const cfg = $('Config critères (défaut)').first().json;
function matchVille(item) {
  const ville = (item.ville || '').toLowerCase();
  const contenu = ((item.quartier || '') + ' ' + (item.description || '') + ' ' + (item.titre || '')).toLowerCase();
  const villesCibles = JSON.parse(cfg.villes_cibles || '[]').map(v => v.toLowerCase());
  if (villesCibles.includes(ville)) return true;
  if (ville === (cfg.ville_speciale || '').toLowerCase()) {
    const quartiersRennes = (cfg.quartiers_rennes_seulement || '').split(',').map(q => q.trim().toLowerCase()).filter(Boolean);
    return quartiersRennes.some(q => contenu.includes(q));
  }
  return false;
}
const output = [];
for (const item of $input.all()) {
  const a = item.json;
  const surface = Number(a.surface_m2 || 0);
  const prix = Number(a.loyer_cc || 0);
  const pieces = Number(a.pieces || 0);
  if (surface < cfg.surface_min_m2 || surface > cfg.surface_max_m2) continue;
  if (prix <= 0 || prix > cfg.prix_max_cc) continue;
  if (pieces < cfg.pieces_min || pieces > cfg.pieces_max) continue;
  if (!matchVille(a)) continue;
  output.push({ json: a });
}
return output;

function normalize(str) {
  return (str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[^a-z0-9 ]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
const j = $input.item.json;
const keyBase = [
  normalize(j.ville),
  normalize(j.quartier),
  normalize(j.titre),
  String(j.surface_m2 || ''),
  String(j.loyer_cc || '')
].join('|');
let hash = 0;
for (let i = 0; i < keyBase.length; i++) {
  hash = ((hash << 5) - hash) + keyBase.charCodeAt(i);
  hash |= 0;
}
j.id_global = 'a_' + Math.abs(hash);
j._isAnnonce = true;
return { json: j };

const all = $input.all();
const annonces = all.filter(i => i.json._isAnnonce === true);
const sheetRows = all.filter(i => i.json._isAnnonce !== true);
function getId(row) {
  const j = row.json;
  const key = Object.keys(j).find(k => k.trim().toLowerCase() === 'id_global');
  return String(key ? j[key] : j.id_global || '').trim();
}
const existingIds = new Set(sheetRows.map(r => getId(r)));
let kept = annonces.filter(a => !existingIds.has(getId(a)));
const seenId = new Set();
kept = kept.filter(a => { const id = getId(a); if (seenId.has(id)) return false; seenId.add(id); return true; });
return kept.map(a => {
  const j = { ...a.json };
  delete j._isAnnonce;
  return { json: j };
});

